              <div style="background-color: #f8fafc; padding: 15px 20px; border-radius: 12px; border: 1px solid #e2e8f0; display: grid; grid-template-columns: repeat(2, 1fr); gap: 8px 20px;">
                ${docChecklistHtml}
              </div>
